ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?copy_editor ?commenttext WHERE {
  ?articles a :Articles .
  ?comments a :Comments .
  ?comments p:hasArticles ?articles .
  ?articles p:Copy_Editor ?copy_editor .
  ?comments p:CommentText ?commenttext .
  ?articles p:Title ?title_f .
  FILTER(STR(?title_f) = "First Article")
} }
  component_2: { SELECT ?managing_editor ?commenttext WHERE {
  ?articles a :Articles .
  ?comments a :Comments .
  ?comments p:hasArticles ?articles .
  ?articles p:Managing_Editor ?managing_editor .
  ?comments p:CommentText ?commenttext .
  ?articles p:Title ?title_f .
  FILTER(STR(?title_f) = "First Article")
} }
  full: { SELECT ?managing_editor ?copy_editor ?commenttext WHERE {
  ?articles a :Articles .
  ?comments a :Comments .
  ?comments p:hasArticles ?articles .
  ?articles p:Managing_Editor ?managing_editor .
  ?articles p:Copy_Editor ?copy_editor .
  ?comments p:CommentText ?commenttext .
  ?articles p:Title ?title_f .
  FILTER(STR(?title_f) = "First Article")
} }
}
